@if (IsLoading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (ErrorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @ErrorMessage
    </div>
}
else if (Products is null || Products.Count == 0)
{
    <div class="alert alert-info text-center" role="alert">
        No products found matching your criteria.
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public List<Product>? Products { get; set; }

    [Parameter]
    public bool IsLoading { get; set; }

    [Parameter]
    public string? ErrorMessage { get; set; }

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => OnPageChanged.InvokeAsync(CurrentPage - 1))"
                        disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var page in GetPageNumbers())
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="@(() => OnPageChanged.InvokeAsync(page))">
                        @page
                    </button>
                </li>
            }

            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => OnPageChanged.InvokeAsync(CurrentPage + 1))"
                        disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private IEnumerable<int> GetPageNumbers()
    {
        // Show up to 5 pages centered on the current page
        int start = Math.Max(1, CurrentPage - 2);
        int end = Math.Min(TotalPages, start + 4);
        start = Math.Max(1, end - 4);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

